sqlReaderQuery.value:
SELECT
    *
FROM adf.DataSource
WHERE
    dataSourceType = 'File System'
    AND (
        NULLIF(NULLIF(LTRIM(RTRIM('@{pipeline().parameters.dataSourceName}')), '-'),'') IS NULL
        OR dataSourceName IN (
            SELECT TRIM(value) FROM STRING_SPLIT('@{pipeline().parameters.dataSourceName}', ',')
        )
    )
    AND (
        NULLIF(NULLIF(LTRIM(RTRIM('@{pipeline().parameters.objectSchema}')), '-'),'') IS NULL
        OR objectSchema IN (
            SELECT TRIM(value) FROM STRING_SPLIT('@{pipeline().parameters.objectSchema}', ',')
        )
    )
    AND (
        NULLIF(NULLIF(LTRIM(RTRIM('@{pipeline().parameters.objectName}')), '-'),'') IS NULL
        OR objectName IN (
            SELECT TRIM(value) FROM STRING_SPLIT('@{pipeline().parameters.objectName}', ',')
        )
    )
    AND (
        NULLIF(NULLIF(LTRIM(RTRIM('@{pipeline().parameters.batchGroup}')), '-'),'') IS NULL
        OR batchGroup IN (
            SELECT TRIM(value) FROM STRING_SPLIT('@{pipeline().parameters.batchGroup}', ',')
        )
    )
    AND isEnabled = 1;

